INSERT INTO feature_flags (key, description, global_enabled, "default") VALUES ('bulk_enrichment_enabled', 'Per-tenant rollout gate for the confirm-before-spend bulk CSV enrichment pipeline (POST /enrichment/jobs/:id/confirm). OFF by default (fail-closed). Effective only when the global BULK_ENRICHMENT_ENABLED env kill-switch is also on; with both on the tenant may release a confirmed bulk-enrich run — which SPENDS credits per match.', false, false) ON CONFLICT (key) DO NOTHING;
